79	bool Deployer::Run() {
80	  LOG(INFO) << "running deployment tasks:";
81	  message_sink_("deploy", "start");
82	  int success = 0;
83	  int failure = 0;
84	  do {
85	    while (auto task = NextTask()) {
86	      try {
87	        if (task->Run(this))
88	          ++success;
89	        else
90	          ++failure;
91	      } catch (const std::exception& ex) {
92	        ++failure;
93	        LOG(ERROR) << "Error deploying: " << ex.what();
94	      }
95	      // boost::this_thread::interruption_point();
96	    }
97	    LOG(INFO) << success + failure << " tasks ran: " << success << " success, "
98	              << failure << " failure.";
99	    message_sink_("deploy", !failure ? "success" : "failure");
100	    // new tasks could have been enqueued while we were sending the message.
101	    // before quitting, double check if there is nothing left to do.
102	  } while (HasPendingTasks());
103	  return !failure;
104	}
