107	  if (IsWorking()) {
108	    LOG(WARNING) << "a work thread is already running.";
109	    return false;
110	  }
111	  maintenance_mode_ = maintenance_mode;
112	  if (pending_tasks_.empty()) {
113	    return false;
114	  }
115	#ifdef RIME_NO_THREADING
116	  LOG(INFO) << "running " << pending_tasks_.size() << " tasks in main thread.";
117	  return Run();
118	#else
119	  LOG(INFO) << "starting work thread for " << pending_tasks_.size()
120	            << " tasks.";
121	  work_ = std::async(std::launch::async, [this] { Run(); });
122	  return work_.valid();
123	#endif
124	}
