65	RIME_DEPRECATED Bool RimeStartMaintenance(Bool full_check) {
66	  LoadModules(kDeployerModules);
67	  Deployer& deployer(Service::instance().deployer());
68	  deployer.RunTask("clean_old_log_files");
69	  if (!deployer.RunTask("installation_update")) {
70	    return False;
71	  }
72	  if (!full_check) {
73	    TaskInitializer args{
74	        vector<path>{
75	            deployer.user_data_dir,
76	            deployer.shared_data_dir,
77	        },
78	    };
79	    if (!deployer.RunTask("detect_modifications", args)) {
80	      return False;
81	    }
82	    LOG(INFO) << "changes detected; starting maintenance.";
83	  }
84	  deployer.ScheduleTask("workspace_update");
85	  deployer.ScheduleTask("user_dict_upgrade");
86	  deployer.ScheduleTask("cleanup_trash");
87	  deployer.StartMaintenance();
88	  return True;
89	}
